/// <summary>
/// Determines if concurrent deletes should throw exception.
/// </summary>
/// <returns>true, if exception should be thrown; otherwise, false.</returns>
public boolean shouldThrowExceptionOnZeroDelete()
{
    return true;
}

/// <summary>
/// Validates the record before it is written.
/// Ensures CourseId is not empty and Name has at least 3 characters.
/// </summary>
/// <returns>true if validation succeeds; otherwise false.</returns>
public boolean validateWrite()
{
    boolean ret;

    ret = super();

    if (!ret)
    {
        return false;
    }

    if (strLen(this.CourseId) == 0)
    {
        error("@ATLCourseManagement:CourseIdRequired");
        return false;
    }

    if (strLen(this.Name) < 3)
    {
        error(strFmt("@ATLCourseManagement:CourseNameMinLength", 3));
        return false;
    }

    return true;
}

public void modifiedField(FieldId _fieldId)
{
    super(_fieldId);
    switch (_fieldId)
    {
        case fieldNum(ATLCourseTable, IsEnabled):
            if (this.IsEnabled == NoYes::No)
            {
                ATLCourseParticipant participant;
                update_recordset participant
                setting IsActive = NoYes::No
                where participant.CourseId == this.CourseId;
            }
            else if (this.IsEnabled == NoYes::Yes)
            {
                ATLCourseParticipant participant;
                update_recordset participant
                setting IsActive = NoYes::Yes
                where participant.CourseId == this.CourseId;
            }
            break;
    }
}

public boolean validateField(FieldId _fieldId)
{
    boolean ret = super(_fieldId);

    if (_fieldId == fieldNum(ATLCourseTable, IsEnabled))
    {
        if (this.IsEnabled == NoYes::No)
        {
            ATLCourseParticipant participant;
            select firstonly participant
            where participant.CourseId == this.CourseId;

            if (participant.RecId != 0)
            {
                if (!Box::yesNo(
                strFmt("@ATLCourseManagement:CourseDisableConfirm", this.Name),
                DialogButton::No))
                {
                    return false;
                }
            }
        }
    }

    return ret;
}

/// <summary>
/// Initializes default values for a new ATLCourseTable record.
/// Sets IsEnabled to Yes so new courses are active by default.
/// </summary>
public void initValue()
{
    super();
    this.IsEnabled = NoYes::Yes;
}
